sample[0]: {'https://doi.org/10.1016/j.techfore.2016.08.019': {'facts': ['Frey and Osborne estimated that 47% of U.S. jobs are at high risk of automation within two decades, particularly those involving routine tasks.'], 'url_content': None}, 'https://doi.org/10.1787/5jlz9h56dvq7-en': {'facts': ['In contrast, Arntz et al. suggested a more conservative 9% of jobs across OECD countries are automatable, emphasizing task-level analysis over occupation-level predictions.'], 'url_content': None}, 'https://doi.org/10.1073/pnas.1900949116': {'facts': ['Frank et al. highlight this discrepancy, noting that studies estimating 9% to 47% of U.S. jobs at risk reflect challenges in modeling AI’s impact due to limited data and evolving technology.', 'Frank et al. identify barriers such as insufficient high-quality data, limited models of skill substitution, and poor understanding of AI’s economic interactions.'], 'url_content': None}, 'https://doi.org/10.1007/s00146-022-01496-x': {'facts': ['Deranty and Corbin provide a comprehensive review, citing pessimistic scenarios where AI could disrupt socio-economic structures.', 'Deranty and Corbin cite optimistic scenarios, noting that AI could boost labor productivity by up to 40% by 2035 (Accenture, 2016) and create a net 58 million jobs by 2030 (World Economic Forum, 2018).', 'Deranty and Corbin highlight concerns about algorithmic management, which increases surveillance and power imbalances, and platform work, which fosters precarity.'], 'url_content': None}, 'https://doi.org/10.1007/s00146-022-01496-x#ref-CR151': {'facts': ['They reference Nedelkoska and Quintini, who estimated 14% of jobs across 32 nations are highly automatable (probability >70%), with 32% at moderate risk (50-70%).'], 'url_content': None}, 'https://doi.org/10.1108/JEBDE-10-2023-0021': {'facts': ['Zarifhonarvar analyzed the effects of ChatGPT, a generative AI model, using a text-mining approach on the International Standard Occupation Classification (ISCO).', 'The study found that 32.8% of occupations could be fully impacted, 36.5% partially impacted, and 30.7% unaffected.', 'Table 1: AI Impact by Occupational Category'], 'url_content': None}, 'https://doi.org/10.1093/pnasnexus/pgae320': {'facts': ['Septiandri et al. introduced the AI Impact (AII) measure, analyzing 17,879 task descriptions against 24,758 AI patents (2015–2022).', 'They found that healthcare, IT, and manufacturing are highly impacted, with roles like cardiovascular technologists (60% of tasks affected) and software developers (47% of tasks) at risk.', 'AI can augment roles like neurologists and air traffic controllers, enhancing productivity without full automation.', 'Table 2: Most and Least Impacted Occupations', 'Septiandri et al. found that small cities face greater automation risks than large ones, while Liu et al. noted higher AI talent demand in states like Washington (32.6%) compared to Alaska (17.4%).'], 'url_content': None}, 'https://doi.org/10.1057/s41599-024-03557-6': {'facts': ['Liu et al. analyzed 279.87 million U.S. job postings (2010–2022), finding a 31-fold increase in demand for AI-specialized statistical talent, diversifying into 932 job roles.', 'Septiandri et al. found that small cities face greater automation risks than large ones, while Liu et al. noted higher AI talent demand in states like Washington (32.6%) compared to Alaska (17.4%).'], 'url_content': None}, 'https://doi.org/10.1007/s00146-022-01496-x#ref-CR1': {'facts': ['Deranty and Corbin cite optimistic scenarios, noting that AI could boost labor productivity by up to 40% by 2035 (Accenture, 2016) and create a net 58 million jobs by 2030 (World Economic Forum, 2018).'], 'url_content': None}, 'https://doi.org/10.1007/s00146-022-01496-x#ref-CR219': {'facts': ['Deranty and Corbin cite optimistic scenarios, noting that AI could boost labor productivity by up to 40% by 2035 (Accenture, 2016) and create a net 58 million jobs by 2030 (World Economic Forum, 2018).'], 'url_content': None}}
